mapper.select:
SELECT hr_id
FROM esg.tb_workers_opinions_on_hazards_info
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}

SELECT write_year
	 , doc_type
	 , doc_no
	 , reg_dt
FROM esg.tb_workers_opinions_on_hazards_info
WHERE comp_id = #{compId}
  AND hr_id = #{hrId}
  AND reg_dt = #{regDt}
  AND USE_YN = 'Y'
ORDER BY reg_dt DESC

SELECT '경험담' || ROW_NUMBER() OVER (ORDER BY experience_no) || E'\n' || content as content
  FROM esg.tb_workers_opinions_on_hazards_experience
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND reg_dt = #{regDt}

mapper.update:
UPDATE esg.tb_workers_opinions_on_hazards_info
   SET worker_opinion = #{workerOpinion}
     , reg_dt = #{regDt}
     , reviewer_opinion = #{reviewerOpinion}
     , workplace_id = #{workplaceId}
     , use_yn = #{useYn}
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}

UPDATE esg.tb_workers_opinions_on_hazards_experience
   SET content = #{content}
     , reg_dt = #{regDt}
     , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND experience_no = #{experienceNo}


UPDATE esg.tb_workers_opinions_on_hazards_info
   SET use_yn = 'N'
   	 , updated_at = now()
     , updated_by = #{updatedBy}
 WHERE write_year = #{writeYear}
   AND hr_id = #{hrId}

mapper.delete:
UPDATE esg.tb_workers_opinions_on_hazards_info
SET use_yn = 'N'
  , updated_at = now()
  , updated_by = #{updatedBy}
WHERE write_year = #{writeYear}
  AND doc_type = #{docType}
  AND doc_no = #{docNo}
  AND hr_id = #{hrId}

DELETE 
  FROM esg.tb_workers_opinions_on_hazards_experience
 WHERE write_year = #{writeYear}
   AND doc_type = #{docType}
   AND doc_no = #{docNo}
   AND experience_no = #{experienceNo}
